package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.ArgumentMatchers.*;
import static org.mockito.Mockito.*;

import java.io.ByteArrayInputStream;
import java.io.IOException;
import java.io.InputStream;
import java.lang.reflect.Field;
import java.nio.charset.StandardCharsets;

import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class CSVParserParseTest {

    @Test
    void parse_withValidInputStreamAndCharsetAndFormat_returnsCSVParser() throws IOException, ReflectiveOperationException {
        // Arrange
        String csvContent = "header1,header2\nvalue1,value2";
        InputStream inputStream = new ByteArrayInputStream(csvContent.getBytes(StandardCharsets.UTF_8));
        CSVFormat format = mock(CSVFormat.class);

        // Use reflection to get the Assertions class and replace the static method notNull temporarily
        Class<?> assertionsClass = Class.forName("org.apache.commons.csv.Assertions");

        try (MockedStatic<CSVParser> mockedCSVParser = Mockito.mockStatic(CSVParser.class)) {
            // Mock CSVParser.parse(Reader, CSVFormat) static method to return a dummy CSVParser
            CSVParser dummyParser = mock(CSVParser.class);
            mockedCSVParser.when(() -> CSVParser.parse(any(java.io.Reader.class), eq(format))).thenReturn(dummyParser);

            // Because Mockito.mockStatic is not available for Assertions (Mockito 3 doesn't support static mocking),
            // we mock the behavior by reflection: replace the Assertions.notNull method with a no-op proxy.
            // But since it's complicated, just skip mocking Assertions.notNull here,
            // assuming it does nothing or throws if null.

            // Act
            CSVParser result = CSVParser.parse(inputStream, StandardCharsets.UTF_8, format);

            // Assert
            assertNotNull(result);
            assertSame(dummyParser, result);

            // Verify that parse(Reader, CSVFormat) was called once
            mockedCSVParser.verify(() -> CSVParser.parse(any(java.io.Reader.class), eq(format)));
        }
    }

    @Test
    void parse_withNullInputStream_throwsNullPointerException() throws ReflectiveOperationException {
        CSVFormat format = mock(CSVFormat.class);

        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse((InputStream) null, StandardCharsets.UTF_8, format));
        assertEquals("inputStream", ex.getMessage());
    }

    @Test
    void parse_withNullFormat_throwsNullPointerException() {
        InputStream inputStream = new ByteArrayInputStream("data".getBytes(StandardCharsets.UTF_8));

        NullPointerException ex = assertThrows(NullPointerException.class, () -> CSVParser.parse(inputStream, StandardCharsets.UTF_8, null));
        assertEquals("format", ex.getMessage());
    }
}
